import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(a, b):
        return np.linalg.norm(a - b)

    if len(unvisited_customers) == 0:
        return None  # Trigger for the truck to wait or return to depot

    weights = np.zeros(len(unvisited_customers))

    for i, customer in enumerate(unvisited_customers):
        dist_to_customer = distance(cur_truck_pos, customer)

        # Calculate weighted score emphasizing closer distances and distancing from crowded areas
        closer_dist_weight = 1 / (1 + dist_to_customer ** 1.2)  # Sharper increase in weight for closer distances

        congestion_penalty = 0
        for other_truck in all_truck_pos:
            prox_to_customer_from_other = distance(other_truck, customer)
            # Intensify penalty based on proximity and number of nearby trucks
            if prox_to_customer_from_other < 1.5 * dist_to_customer:
                congestion_penalty += 0.5 * (1.5 - prox_to_customer_from_other / dist_to_customer)

        # Combining weights considering proximity and reduced congestion influence
        weights[i] = closer_dist_weight - 0.7 * congestion_penalty

    best_node = np.argmax(weights)

    return best_node
